import React, { useEffect, useRef, useState } from 'react';
import axios from 'axios';
import { io } from 'socket.io-client';

const PRIMARY_BLUE = '#007BFF';

const AdminDashboard = () => {
  const [loading, setLoading] = useState(true);
  const [tutors, setTutors] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [users, setUsers] = useState([]);
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState('overview');
  const [liveMessages, setLiveMessages] = useState([]);

  const socketRef = useRef(null);

  const token = typeof window !== 'undefined'
    ? localStorage.getItem('ethioBooksToken')
    : null;

  const api = axios.create({
    baseURL: 'http://localhost:5000/api',
    headers: token
      ? {
          Authorization: `Bearer ${token}`
        }
      : {}
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      setError('');

      const [pendingTutorsRes, pendingTxRes, usersRes] = await Promise.all([
        api.get('/admin/pending-tutors'),
        api.get('/admin/pending-transactions'),
        api.get('/admin/users')
      ]);

      setTutors(pendingTutorsRes.data || []);
      setTransactions(pendingTxRes.data || []);
      setUsers(usersRes.data || []);
    } catch (err) {
      console.error(err);
      const message =
        err.response?.data?.message || 'Failed to load admin data.';
      setError(message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!token) {
      setError('No admin token found. Please log in as admin.');
      setLoading(false);
      return;
    }

    fetchData();

    const socket = io('http://localhost:5000', {
      auth: { token }
    });

    socketRef.current = socket;

    socket.on('connect_error', (err) => {
      console.error('Socket connection error:', err.message);
    });

    socket.on('newMessage', (message) => {
      setLiveMessages((prev) => [message, ...prev].slice(0, 100));
    });

    return () => {
      socket.disconnect();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const totalStudents = users.filter((u) => u.role === 'student').length;
  const totalTutors = users.filter((u) => u.role === 'tutor').length;
  const pendingApprovals = tutors.length + transactions.length;

  const handleApproveTutor = async (id) => {
    try {
      await api.patch(`/admin/approve-tutor/${id}`);
      await fetchData();
    } catch (err) {
      console.error(err);
      const message =
        err.response?.data?.message || 'Failed to approve tutor.';
      alert(message);
    }
  };

  const handleViewDocs = (docs = []) => {
    if (!docs || docs.length === 0) {
      alert('No documents uploaded for this tutor.');
      return;
    }
    // Open first document; you can extend this to show all
    window.open(docs[0], '_blank', 'noopener,noreferrer');
  };

  const handleApprovePremium = async (id) => {
    try {
      await api.patch(`/admin/approve-premium/${id}`);
      await fetchData();
    } catch (err) {
      console.error(err);
      const message =
        err.response?.data?.message || 'Failed to approve premium.';
      alert(message);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <header
        className="w-full shadow-sm bg-white"
        style={{ borderBottom: '3px solid rgba(0,123,255,0.12)' }}
      >
        <div className="max-w-6xl mx-auto px-4 py-4 flex items-center justify-between">
          <h1
            className="text-2xl font-bold tracking-tight"
            style={{ color: PRIMARY_BLUE }}
          >
            Ethio Books Admin
          </h1>
          <span className="text-xs text-gray-500">
            Logged in as <span className="font-semibold">Admin</span>
          </span>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-6 space-y-6">
        {error && (
          <div className="rounded-lg border border-red-200 bg-red-50 px-4 py-2 text-sm text-red-700">
            {error}
          </div>
        )}

        {/* Tabs */}
        <div className="flex items-center border-b border-gray-200 mb-2">
          <button
            type="button"
            onClick={() => setActiveTab('overview')}
            className={`px-3 py-2 text-xs font-semibold border-b-2 -mb-px ${
              activeTab === 'overview'
                ? 'border-blue-500 text-blue-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            Overview
          </button>
          <button
            type="button"
            onClick={() => setActiveTab('live')}
            className={`ml-2 px-3 py-2 text-xs font-semibold border-b-2 -mb-px ${
              activeTab === 'live'
                ? 'border-blue-500 text-blue-600'
                : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            Live Feed
          </button>
        </div>

        {activeTab === 'overview' && (
          <>
            {/* Stats Cards */}
            <section className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-col justify-between">
            <div className="flex items-center justify-between">
              <span className="text-xs font-semibold text-gray-500 uppercase">
                Total Students
              </span>
            </div>
            <div className="mt-2 flex items-end justify-between">
              <p className="text-3xl font-bold text-gray-900">
                {loading ? '—' : totalStudents}
              </p>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-col justify-between">
            <div className="flex items-center justify-between">
              <span className="text-xs font-semibold text-gray-500 uppercase">
                Total Tutors
              </span>
            </div>
            <div className="mt-2 flex items-end justify-between">
              <p className="text-3xl font-bold text-gray-900">
                {loading ? '—' : totalTutors}
              </p>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-col justify-between">
            <div className="flex items-center justify-between">
              <span className="text-xs font-semibold text-gray-500 uppercase">
                Pending Approvals
              </span>
            </div>
            <div className="mt-2 flex items-end justify-between">
              <p
                className="text-3xl font-bold"
                style={{ color: PRIMARY_BLUE }}
              >
                {loading ? '—' : pendingApprovals}
              </p>
            </div>
          </div>
            </section>

            {/* Main grid: Tutor approvals + Payments + Live Chat */}
            <section className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Tutor Approval Table */}
          <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-100 p-4">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-sm font-semibold text-gray-800">
                Pending Tutor Approvals
              </h2>
              <span className="text-xs text-gray-500">
                {tutors.length} tutor(s)
              </span>
            </div>
            <div className="overflow-x-auto">
              <table className="min-w-full text-left text-xs">
                <thead>
                  <tr className="border-b border-gray-100 text-gray-500">
                    <th className="py-2 pr-4">Name</th>
                    <th className="py-2 pr-4">Education</th>
                    <th className="py-2 pr-4">Status</th>
                    <th className="py-2 pr-4 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {tutors.length === 0 && (
                    <tr>
                      <td
                        colSpan={4}
                        className="py-4 text-center text-gray-400"
                      >
                        No pending tutors.
                      </td>
                    </tr>
                  )}
                  {tutors.map((tutor) => (
                    <tr
                      key={tutor._id}
                      className="border-b border-gray-50 hover:bg-gray-50/60"
                    >
                      <td className="py-2 pr-4 text-gray-800">
                        {tutor.fullName}
                      </td>
                      <td className="py-2 pr-4 text-gray-600">
                        {tutor.educationLevel || '—'}
                      </td>
                      <td className="py-2 pr-4">
                        <span className="inline-flex items-center rounded-full bg-yellow-50 px-2 py-0.5 text-[10px] font-medium text-yellow-700">
                          {tutor.tutorStatus}
                        </span>
                      </td>
                      <td className="py-2 pr-4">
                        <div className="flex items-center justify-end space-x-2">
                          <button
                            type="button"
                            onClick={() => handleViewDocs(tutor.docs)}
                            className="px-2 py-1 text-[11px] rounded-md border border-gray-200 text-gray-700 hover:bg-gray-100 transition"
                          >
                            View Docs
                          </button>
                          <button
                            type="button"
                            onClick={() => handleApproveTutor(tutor._id)}
                            className="px-3 py-1 text-[11px] font-semibold rounded-md text-white shadow-sm hover:shadow-md transition"
                            style={{ backgroundColor: PRIMARY_BLUE }}
                          >
                            Approve
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Live Chat Monitor placeholder */}
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-col">
            <h2 className="text-sm font-semibold text-gray-800 mb-3">
              Live Chat Monitor
            </h2>
            <div className="flex-1 rounded-lg border border-dashed border-gray-200 bg-gray-50 flex items-center justify-center px-3 py-4 text-center">
              <div>
                <p className="text-xs text-gray-500">
                  Real-time DM feed will appear here.
                </p>
                <p className="mt-1 text-[11px] text-gray-400">
                  Integrate WebSockets or a real-time service to populate this
                  section.
                </p>
              </div>
            </div>
          </div>
        </section>

            {/* Payment Verification */}
            <section className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
          <div className="flex items-center justify-between mb-3">
            <h2 className="text-sm font-semibold text-gray-800">
              Payment Verification
            </h2>
            <span className="text-xs text-gray-500">
              {transactions.length} pending transaction(s)
            </span>
          </div>

          {transactions.length === 0 ? (
            <p className="py-4 text-center text-gray-400 text-xs">
              No pending payment verifications.
            </p>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {transactions.map((tx) => (
                <div
                  key={tx._id}
                  className="border border-gray-100 rounded-lg shadow-sm bg-white overflow-hidden flex flex-col"
                >
                  <div className="h-32 bg-gray-100 flex items-center justify-center overflow-hidden">
                    {/* Screenshot image */}
                    <img
                      src={tx.screenshotUrl}
                      alt="Payment receipt"
                      className="max-h-full w-full object-contain"
                    />
                  </div>
                  <div className="p-3 space-y-1 text-xs text-gray-700 flex-1">
                    <p className="font-semibold text-gray-800">
                      {tx.student?.fullName || 'Unknown Student'}
                    </p>
                    <p className="text-gray-500">
                      Grade {tx.student?.grade || '—'} •{' '}
                      {tx.student?.schoolName || 'School N/A'}
                    </p>
                    <p className="text-gray-500">
                      Phone: {tx.student?.phone || '—'}
                    </p>
                  </div>
                  <div className="p-3 pt-0 flex justify-between items-center">
                    <span className="inline-flex items-center rounded-full bg-yellow-50 px-2 py-0.5 text-[10px] font-medium text-yellow-700">
                      {tx.status}
                    </span>
                    <button
                      type="button"
                      onClick={() => handleApprovePremium(tx._id)}
                      className="px-3 py-1 text-[11px] font-semibold rounded-md text-white shadow-sm hover:shadow-md transition"
                      style={{ backgroundColor: PRIMARY_BLUE }}
                    >
                      Approve Premium
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
          </>
        )}

        {activeTab === 'live' && (
          <section className="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
            <div className="flex items-center justify-between mb-3">
              <h2 className="text-sm font-semibold text-gray-800">
                Live DM Feed
              </h2>
              <span className="text-xs text-gray-500">
                {liveMessages.length} recent message(s)
              </span>
            </div>
            {liveMessages.length === 0 ? (
              <p className="text-xs text-gray-400 py-4">
                No messages yet. Live messages will appear here in real-time.
              </p>
            ) : (
              <div className="max-h-[480px] overflow-y-auto space-y-2 text-xs">
                {liveMessages.map((msg) => (
                  <div
                    key={msg.id}
                    className="border border-gray-100 rounded-lg px-3 py-2 bg-gray-50"
                  >
                    <div className="flex items-center justify-between mb-1">
                      <div className="flex items-center space-x-2">
                        <span className="font-semibold text-gray-800">
                          {msg.sender?.fullName || 'Unknown'}
                        </span>
                        <span className="text-[10px] text-gray-500">
                          → {msg.receiver?.fullName || 'Unknown'}
                        </span>
                      </div>
                      <span className="text-[10px] text-gray-400">
                        {msg.timestamp
                          ? new Date(msg.timestamp).toLocaleTimeString()
                          : ''}
                      </span>
                    </div>
                    <p className="text-gray-700 text-[11px]">{msg.text}</p>
                    <p className="mt-1 text-[10px] text-gray-400">
                      Room: {msg.roomId}
                    </p>
                  </div>
                ))}
              </div>
            )}
          </section>
        )}
      </main>
    </div>
  );
};

export default AdminDashboard;
